import scala.annotation.tailrec

def solve(nums: Array[Long]): Long = {
  val n = nums.length
  val totalFull = if (n > 0) nums.reduce(_ ^ _) else 0L
  val size = 1 << n
  val xorMask = Array.ofDim[Long](size)
  val andMask = Array.ofDim[Long](size)

  for (mask <- 0 until size) {
    if (mask == 0) {
      xorMask(mask) = 0L
      andMask(mask) = 0L
    } else {
      var xor: Long = 0
      var tempAnd: Long = -1L
      var first = true
      for (i <- 0 until n) {
        if ((mask & (1 << i)) != 0) {
          xor ^= nums(i)
          if (first) {
            tempAnd = nums(i)
            first = false
          } else {
            tempAnd &= nums(i)
          }
        }
      }
      xorMask(mask) = xor
      andMask(mask) = tempAnd
    }
  }

  var ans = 0L
  for (maskB <- 0 until size) {
    val maskS = ((1 << n) - 1) ^ maskB
    val andB = andMask(maskB)
    val totalS = totalFull ^ xorMask(maskB)
    var innerMax = 0L
    var current = maskS
    var continue = true
    while (continue) {
      val xorA = xorMask(current)
      val xorC = totalS ^ xorA
      val totalInner = xorA + xorC
      if (totalInner > innerMax) innerMax = totalInner
      if (current == 0) {
        continue = false
      } else {
        current = (current - 1) & maskS
      }
    }
    val candidate = andB + innerMax
    if (candidate > ans) ans = candidate
  }
  ans
}
```

